sql:
SELECT rideable_type
FROM rides
WHERE duration > 60 AND traffic_conditions = 'traffic jam';

SELECT SUM(duration) AS total_duration
FROM rides
WHERE promotion_id IS NOT NULL;

SELECT rideable_type, AVG(duration) AS average_duration
FROM rides
GROUP BY rideable_type;

SELECT user_id, SUM(duration) AS total_duration
FROM rides
GROUP BY user_id;

SELECT COUNT(DISTINCT user_id) AS num_of_users
FROM rides
WHERE start_time >= 'YYYY-MM-DD 00:00:00' AND start_time <= 'YYYY-MM-DD 23:59:59';

SELECT promotion_id, promotion_code, usage_count
FROM promotions
ORDER BY usage_count DESC;

SELECT type_id, type_name
FROM rideable_types
WHERE battery_capacity > 100;

SELECT weather_conditions, AVG(available_bikes) AS 'Average Available Bikes'
FROM station_status
GROUP BY weather_conditions;

SELECT usage_count, max_usage
FROM promotions
WHERE promotion_code = 'SPRING20';

SELECT title, COUNT(*) AS report_count 
FROM usage_reports 
GROUP BY title;

SELECT DISTINCT user_name
FROM users
WHERE user_id IN (SELECT user_id FROM payments);

SELECT * 
FROM promotions 
WHERE usage_count > (SELECT AVG(usage_count) FROM promotions);

SELECT promotion_id, description, start_date, end_date, target_group, promotion_code
FROM promotions
WHERE usage_count = 0;

SELECT ride_id 
FROM rides
WHERE start_station_id = 1;

